local OIIOIlIOOOI=90
local OOllIOOlIll=216
local OlII0OI000l="ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local function OO0IIIl0000(d)
    d=(d or ""):gsub("%s+","")
    d=d:gsub("[^"..OlII0OI000l.."=]","")
    return (d:gsub(".",function(x)
        if x=="=" then return "" end
        local r,f="",(OlII0OI000l:find(x,1,true)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and "1" or "0")
        end
        return r
    end):gsub("%d%d%d?%d?%d?%d?%d?%d?",function(x)
        if #x~=8 then return "" end
        local c=0
        for i=1,8 do
            if x:sub(i,i)=="1" then c=c+2^(8-i) end
        end
        return string.char(c)
    end))
end
local function O0l00lIIIIl(a,b)
    local r,m=0,1
    while a>0 or b>0 do
        local aa=a%2
        local bb=b%2
        if aa~=bb then r=r+m end
        a=(a-aa)/2
        b=(b-bb)/2
        m=m*2
    end
    return r
end
local OIIlOOOOlIO=OIOlII0I0IO:gsub("[^A-Za-z0-9+/=]","")
OIIlOOOOlIO=string.reverse(OIIlOOOOlIO)
local OIO0lO000OO=OO0IIIl0000(OIIlOOOOlIO)
local O0IlOIl0I00={}
for OlllOlIII0O=1,#OIO0lO000OO do
    local OOO0IOIOlOO=OIO0lO000OO:byte(OlllOlIII0O)
    local Ol0OIOI0IIl=(OOO0IOIOlOO-((OOllIOOlIll+OlllOlIII0O)%256))%256
    O0IlOIl0I00[OlllOlIII0O]=string.char(O0l00lIIIIl(Ol0OIOI0IIl,OIIOIlIOOOI))
end
local OOl00lOl0OO=table.concat(O0IlOIl0I00)
local OlIlIOOOlO0=loadstring or load
local OlIOllI0lII,OIlOIIO0llO=OlIlIOOOlO0(OOl00lOl0OO)
if not OlIOllI0lII then error(OIlOIIO0llO) end
return OlIOllI0lII()
